    "title": "Família que convivia com Michael Jackson acusa cantor de abuso sexual; entenda caso",
    "eyebrow": "cultura",
    "date": "24 de abr. de 2026",
    "publishedAt": "2026-04-24T21:08:06.000Z",
    "category": "Cultura",
    "categoryKey": "cultura",
