    "id": "https://g1.globo.com/economia/noticia/2026/04/24/bc-barra-no-brasil-mercados-preditivos-sobre-eleicoes-esportes-e-reality-shows.ghtml",
    "slug": "brasil-barra-plataformas-de-previsoes-em-politica-e-esporte-decisao-nao-afeta-bets",
    "title": "Brasil barra plataformas de previsões em política e esporte; decisão não afeta bets",
    "eyebrow": "esporte",
    "date": "24 de abr. de 2026",
    "publishedAt": "2026-04-24T16:19:11.000Z",
    "category": "Esporte",
    "categoryKey": "esporte",
